function solve(grid: number[][], x: number, y: number, k: number): number[][] {
    // Create a copy of the grid to avoid modifying the original
    const result = grid.map(row => [...row]);

    // Extract the submatrix
    const submatrix = result.slice(x, x + k).map(row => row.slice(y, y + k));

    // Reverse the submatrix vertically
    const reversedSubmatrix = submatrix.reverse();

    // Replace the original submatrix with the reversed one
    let index = 0;
    for (let i = x; i < x + k; i++) {
        for (let j = y; j < y + k; j++) {
            result[i][j] = reversedSubmatrix[index][j - y];
            index++;
        }
    }

    return result;
}

